import { Link, useNavigate } from "react-router-dom";

export default function Navbar() {
  const navigate = useNavigate();
  const token = localStorage.getItem("token");
  const role = localStorage.getItem("role");

  const logout = () => {
    localStorage.clear();
    navigate("/login");
  };

  return (
    <nav style={{ padding: 10, background: "#222", color: "#fff", display: "flex", gap: 12 }}>
      <Link to="/" style={{ color: "#fff" }}>Home</Link>
      <Link to="/vehicles" style={{ color: "#fff" }}>Vehicles</Link>

      {!token && (
        <>
          <Link to="/login" style={{ color: "#fff" }}>Login</Link>
          <Link to="/register" style={{ color: "#fff" }}>Register</Link>
        </>
      )}

      {token && role === "client" && (
        <>
          <Link to="/book-appointment" style={{ color: "#fff" }}>Book</Link>
          <Link to="/my-appointments" style={{ color: "#fff" }}>My Appointments</Link>
          <button onClick={logout}>Logout</button>
        </>
      )}

      {token && (role === "staff" || role === "manager" || role === "admin") && (
        <>
          <Link to="/appointments" style={{ color: "#fff" }}>Appointments</Link>
          {(role === "manager" || role === "admin") && (
            <Link to="/vehicles/add" style={{ color: "#fff" }}>Add Vehicle</Link>
          )}
          {role === "admin" && (
            <Link to="/admin/create-staff" style={{ color: "#fff" }}>Create Staff</Link>
          )}
          <button onClick={logout}>Logout</button>
        </>
      )}
    </nav>
  );
}
